1242	+/// Look up `proc_nr`'s `(priority, quantum)`, lazily registering it at the
1243	+/// default managed band + quantum if unseen (the `SCHEDULING_NO_QUANTUM` path —
1244	+/// the kernel pre-delegates a proc, so SCHED meets it for the first time on its
1245	+/// first no-quantum event). Returns `None` only if the table is full and
1246	+/// `proc_nr` is new.
1247	+fn schedule_in(t: &mut [SchedProc; CAP], proc_nr: i32) -> Option<(u8, i32)> {
1248	+    for e in t.iter() {
1249	+        if e.in_use && e.proc_nr == proc_nr {
1250	+            return Some((e.priority, e.quantum));
1251	+        }
1252	+    }
1253	+    for e in t.iter_mut() {
1254	+        if !e.in_use {
1255	+            *e = SchedProc {
1256	+                proc_nr,
1257	+                priority: USER_Q,
1258	+                quantum: QUANTUM,
1259	+                in_use: true,
1260	+            };
1261	+            return Some((USER_Q, QUANTUM));
1262	+        }
1263	+    }
1264	+    None
1265	+}
1266	+
1267	+/// Record (or update) `proc_nr`'s managed priority + quantum — the
1268	+/// `SCHEDULING_START` / `SCHEDULING_SET_NICE` path. Returns false only if the
1269	+/// table is full and `proc_nr` is new.
1270	+fn record_in(t: &mut [SchedProc; CAP], proc_nr: i32, priority: u8, quantum: i32) -> bool {
1271	+    for e in t.iter_mut() {
1272	+        if e.in_use && e.proc_nr == proc_nr {
1273	+            e.priority = priority;
1274	+            e.quantum = quantum;
1275	+            return true;
1276	+        }
1277	+    }
1278	+    for e in t.iter_mut() {
1279	+        if !e.in_use {
1280	+            *e = SchedProc {
1281	+                proc_nr,
1282	+                priority,
1283	+                quantum,
1284	+                in_use: true,
1285	+            };
1286	+            return true;
1287	+        }
1288	+    }
1289	+    false
1290	+}
1291	+
1292	+/// Stop managing `proc_nr` (the `SCHEDULING_STOP` path). No-op if absent.
1293	+fn forget_in(t: &mut [SchedProc; CAP], proc_nr: i32) {
1294	+    for e in t.iter_mut() {
1295	+        if e.in_use && e.proc_nr == proc_nr {
1296	+            *e = SchedProc::EMPTY;
1297	+            return;
1298	+        }
1299	+    }
1300	+}
1301	+
1302	+/// `UnsafeCell`-wrapped static policy table. See the module note for the
1303	+/// single-mutator invariant that makes the `Sync` impl sound.
1304	+#[repr(transparent)]
1305	+struct Table(UnsafeCell<[SchedProc; CAP]>);
1306	+
1307	+// SAFETY: SCHED is a single-threaded EL0 process with no interrupt handlers of
1308	+// its own; the table is only ever accessed from SCHED's straight-line receive
1309	+// loop, so there is never concurrent access.
1310	+unsafe impl Sync for Table {}
1311	+
1312	+static TABLE: Table = Table(UnsafeCell::new([SchedProc::EMPTY; CAP]));
1313	+
1314	+/// Look up (lazily registering at the default band) `proc_nr`'s scheduling
1315	+/// parameters. See [`schedule_in`].
1316	+#[cfg_attr(test, allow(dead_code))]
1317	+pub fn schedule_proc(proc_nr: i32) -> Option<(u8, i32)> {
1318	+    // SAFETY: single-mutator invariant (module note); no other reference into
1319	+    // the table is live during SCHED's straight-line loop.
1320	+    let t = unsafe { &mut *TABLE.0.get() };
1321	+    schedule_in(t, proc_nr)
1322	+}
1323	+
1324	+/// Record (or update) `proc_nr`'s managed priority + quantum. See [`record_in`].
1325	+#[cfg_attr(test, allow(dead_code))]
1326	+pub fn record(proc_nr: i32, priority: u8, quantum: i32) -> bool {
1327	+    // SAFETY: single-mutator invariant (module note).
1328	+    let t = unsafe { &mut *TABLE.0.get() };
1329	+    record_in(t, proc_nr, priority, quantum)
1330	+}
1331	+
1332	+/// Stop managing `proc_nr`. See [`forget_in`].
1333	+#[cfg_attr(test, allow(dead_code))]
1334	+pub fn forget(proc_nr: i32) {
1335	+    // SAFETY: single-mutator invariant (module note).
1336	+    let t = unsafe { &mut *TABLE.0.get() };
1337	+    forget_in(t, proc_nr)
1338	+}
1339	+
1340	+#[cfg(test)]
1341	+mod tests {
1342	+    use super::*;
1343	+
1344	+    #[test]
1345	+    fn first_sight_registers_at_default_band() {
1346	+        let mut t = [SchedProc::EMPTY; CAP];
1347	+        assert_eq!(schedule_in(&mut t, 13), Some((USER_Q, QUANTUM)));
1348	+        // The slot is now in use and stable on the next lookup.
1349	+        assert_eq!(schedule_in(&mut t, 13), Some((USER_Q, QUANTUM)));
1350	+        let used = t.iter().filter(|e| e.in_use).count();
1351	+        assert_eq!(
1352	+            used, 1,
1353	+            "a repeat no-quantum must not consume a second slot"
1354	+        );
1355	+    }
1356	+
1357	+    #[test]
1358	+    fn record_then_schedule_returns_recorded_values() {
1359	+        let mut t = [SchedProc::EMPTY; CAP];
1360	+        assert!(record_in(&mut t, 9, 6, 20));
1361	+        assert_eq!(schedule_in(&mut t, 9), Some((6, 20)));
1362	+    }
1363	+
1364	+    #[test]
1365	+    fn record_updates_in_place() {
1366	+        let mut t = [SchedProc::EMPTY; CAP];
1367	+        assert!(record_in(&mut t, 9, 6, 20));
1368	+        assert!(record_in(&mut t, 9, 10, 5));
1369	+        assert_eq!(schedule_in(&mut t, 9), Some((10, 5)));
1370	+        let used = t.iter().filter(|e| e.in_use).count();
1371	+        assert_eq!(used, 1);
1372	+    }
1373	+
1374	+    #[test]
1375	+    fn forget_frees_the_slot() {
1376	+        let mut t = [SchedProc::EMPTY; CAP];
1377	+        schedule_in(&mut t, 13);
1378	+        forget_in(&mut t, 13);
1379	+        assert_eq!(t.iter().filter(|e| e.in_use).count(), 0);
1380	+        // forgetting an absent proc is a no-op
1381	+        forget_in(&mut t, 99);
1382	+        assert_eq!(t.iter().filter(|e| e.in_use).count(), 0);
1383	+    }
1384	+
1385	+    #[test]
1386	+    fn distinct_procs_coexist() {
1387	+        let mut t = [SchedProc::EMPTY; CAP];
1388	+        schedule_in(&mut t, 11);
1389	+        schedule_in(&mut t, 12);
1390	+        record_in(&mut t, 13, 4, 30);
1391	+        assert_eq!(schedule_in(&mut t, 11), Some((USER_Q, QUANTUM)));
1392	+        assert_eq!(schedule_in(&mut t, 12), Some((USER_Q, QUANTUM)));
1393	+        assert_eq!(schedule_in(&mut t, 13), Some((4, 30)));
1394	+    }
1395	+
1396	+    #[test]
1397	+    fn full_table_leaves_new_proc_unmanaged() {
1398	+        let mut t = [SchedProc::EMPTY; CAP];
1399	+        for i in 0..CAP as i32 {
1400	+            assert!(record_in(&mut t, i, USER_Q, QUANTUM));
1401	+        }
1402	+        // A new proc has nowhere to go.
1403	+        assert_eq!(schedule_in(&mut t, 100), None);
1404	+        assert!(!record_in(&mut t, 100, USER_Q, QUANTUM));
1405	+        // But an already-managed proc still resolves.
1406	+        assert_eq!(schedule_in(&mut t, 0), Some((USER_Q, QUANTUM)));
1407	+    }
1408	+}
