1415	+/*
1416	+ * minix.rs user-space linker script (aarch64 EL0 servers).
1417	+ *
1418	+ * Produces a static ET_EXEC ELF that the kernel's minimal loader
1419	+ * (`kernel/src/boot_image/elf.rs`) maps segment-by-segment into a fresh
1420	+ * per-process AddrSpace. The loader is deliberately tiny, so this script
1421	+ * keeps every PT_LOAD page-aligned (vaddr *and* file offset) and emits no
1422	+ * dynamic sections / relocations.
1423	+ *
1424	+ * Load base 0x0010_0000 (1 MiB): comfortably below USER_VA_TOP and clear of
1425	+ * the kernel's hand-coded EL0 stub VAs (code 0x40_0000-0x43_0000, stacks
1426	+ * 0x80_0000-0x83_0000, stub-D heap 0x0100_0000). The stack is NOT part of
1427	+ * the ELF — the kernel allocates a stack frame and sets SP_EL0 before eret.
1428	+ * Each server gets its own per-process TTBR0, so this shared load base
1429	+ * never collides across servers.
1430	+ */
1431	+
1432	+OUTPUT_FORMAT(elf64-littleaarch64)
1433	+OUTPUT_ARCH(aarch64)
1434	+ENTRY(_start)
1435	+
1436	+PHDRS {
1437	+    text   PT_LOAD FLAGS(5); /* R+X */
1438	+    rodata PT_LOAD FLAGS(4); /* R   */
1439	+    data   PT_LOAD FLAGS(6); /* RW  */
1440	+}
1441	+
1442	+SECTIONS {
1443	+    . = 0x00100000;
1444	+
1445	+    .text : ALIGN(4K) {
1446	+        KEEP(*(.text._start))
1447	+        *(.text .text.*)
1448	+    } :text
1449	+
1450	+    . = ALIGN(4K);
1451	+    .rodata : ALIGN(4K) {
1452	+        *(.rodata .rodata.*)
1453	+    } :rodata
1454	+
1455	+    . = ALIGN(4K);
1456	+    .data : ALIGN(4K) {
1457	+        *(.data .data.*)
1458	+    } :data
1459	+
1460	+    .bss : ALIGN(4K) {
1461	+        *(.bss .bss.*)
1462	+        *(COMMON)
1463	+    } :data
1464	+
1465	+    /DISCARD/ : {
1466	+        *(.eh_frame)
1467	+        *(.eh_frame_hdr)
1468	+        *(.note .note.*)
1469	+        *(.comment)
1470	+        *(.dynsym .dynstr .hash .gnu.hash .dynamic)
1471	+    }
1472	+}
