+// its own; the table is only ever accessed from SCHED's straight-line receive
+// loop, so there is never concurrent access.
+unsafe impl Sync for Table {}
+
+static TABLE: Table = Table(UnsafeCell::new([SchedProc::EMPTY; CAP]));
