pub fn record(proc_nr: i32, priority: u8, quantum: i32) -> bool {
    // SAFETY: single-mutator invariant (module note).
    let t = unsafe { &mut *TABLE.0.get() };
    record_in(t, proc_nr, priority, quantum)
